#include <iostream>
using namespace std;

// Function that accepts double but receives int (implicit casting)
double calculateArea(int radius) {
    return 3.14159 * radius * radius;
}

// Function with explicit return type
int getIntegerPart(double value) {
    return value;  // Implicit casting from double to int
}

int main() {
    int r = 5;
    double area = calculateArea(r);  // int implicitly cast to double
    cout << "Radius: " << r << endl;
    cout << "Area: " << area << endl;

    double num = 9.87;
    int part = getIntegerPart(num);  // double implicitly cast to int
    cout << "Number: " << num << endl;
    cout << "Integer Part: " << part << endl;

    return 0;
}

#include <iostream>
using namespace std;

// Function overloading for different types
int add(int a, int b) {
    cout << "Integer addition called" << endl;
    return a + b;
}

double add(double a, double b) {
    cout << "Double addition called" << endl;
    return a + b;
}

// Function demonstrating explicit casting
void demonstrateCasting() {
    double pi = 3.14159;
    int intPi = static_cast<int>(pi);  // Explicit cast: double to int
    cout << "Original double: " << pi << endl;
    cout << "After static_cast<int>: " << intPi << endl;

    int num = 100;
    char ch = static_cast<char>(num);  // Explicit cast: int to char
    cout << "Integer: " << num << " -> Character: " << ch << endl;

    // C-style cast (not recommended but important to know)
    double result = (double)num / 3;  // C-style cast
    cout << "C-style cast result: " << result << endl;

    // const_cast (removing const)
    const int constVal = 50;
    int* ptr = const_cast<int*>(&constVal);
    cout << "Using const_cast: " << *ptr << endl;
}

int main() {
    // Function overloading in action
    cout << add(5, 10) << endl;
    cout << add(2.5, 3.7) << endl;

    // Explicit type casting demonstration
    demonstrateCasting();

    return 0;
}

#include <iostream>
using namespace std;

// Template function with type requirements
template<typename T>
T multiply(T a, T b) {
    return a * b;
}

// Template with explicit type conversion
template<typename T, typename U>
auto addTyped(T a, U b) -> decltype(a + b) {
    return a + b;  // Return type deduced from expression
}

// Inline function for performance
inline int compare(int a, int b) {
    return (a > b) ? a : b;
}

// Reference parameters with const
void modifyValue(int& ref) {
    ref *= 2;
}

void displayValue(const int& ref) {
    cout << "Read-only value: " << ref << endl;
}

// Demonstrating type conversion in class context
class Number {
private:
    double value;
public:
    Number(double v) : value(v) {}

    // Conversion operator: Number to int
    operator int() const {
        return static_cast<int>(value);
    }

    // Conversion operator: Number to double
    operator double() const {
        return value;
    }

    void display() const {
        cout << "Number value: " << value << endl;
    }
};

int main() {
    // Template function usage
    cout << "Template multiply(int): " << multiply(5, 4) << endl;
    cout << "Template multiply(double): " << multiply(2.5, 3.0) << endl;

    // Mixed type template with auto return
    auto result = addTyped(10, 5.5);
    cout << "Mixed type add: " << result << " (type deduced)" << endl;

    // Inline function
    cout << "Inline compare: " << compare(10, 20) << endl;

    // Reference parameters
    int x = 25;
    modifyValue(x);
    cout << "After modifyValue: " << x << endl;
    displayValue(x);

    // Class with conversion operators
    Number num(7.89);
    num.display();

    int convertedInt = num;  // Implicit conversion using operator int()
    double convertedDouble = num;  // Implicit conversion using operator double()
    cout << "Converted to int: " << convertedInt << endl;
    cout << "Converted to double: " << convertedDouble << endl;

    // Explicit cast using conversion operator
    int explicitInt = static_cast<int>(num);
    cout << "Explicit static_cast<int>: " << explicitInt << endl;

    return 0;
}
